# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transaction(account_balances, account_id, transaction_type, amount):
    if account_id not in account_balances:
        return "Invalid account ID"
    
    if transaction_type == "debit":
        if account_balances[account_id] >= amount:
            account_balances[account_id] -= amount 
        else:
            return "Insufficient balance"
    elif transaction_type == "credit":
        account_balances[account_id] += amount
    else:
        return "Invalid Transaction type"

    return account_balances